"use client";

import { useState, useRef } from "react";
import ChampionCard from "./ChampionCard";

function mod(n, m) {
  return ((n % m) + m) % m;
}

// x is in px offset from center (not %)
const SLOT_CONFIG = {
  "-2": { xPx: -420, scale: 0.55, opacity: 0.18, z: 10, rotate: 0 },
  "-1": { xPx: -230, scale: 0.77, opacity: 0.55, z: 20, rotate: 0 },
   "0": { xPx:    0, scale: 1.00, opacity: 1.00, z: 40, rotate: 0 },
   "1": { xPx:  230, scale: 0.77, opacity: 0.55, z: 20, rotate: 0 },
   "2": { xPx:  420, scale: 0.55, opacity: 0.18, z: 10, rotate: 0 },
};

function SideCard({ champ }) {
  return (
    <div className="relative w-full overflow-hidden rounded-2xl pointer-events-none" style={{ aspectRatio: "3/4" }}>
      {champ.photo ? (
        <img src={champ.photo} alt={champ.name}
          className="absolute inset-0 w-full h-full object-cover object-top" />
      ) : (
        <div className="absolute inset-0 bg-zinc-900 flex items-center justify-center">
          <span className="text-5xl text-zinc-700">👤</span>
        </div>
      )}
      <div className="absolute inset-0"
        style={{ background: "linear-gradient(to top, rgba(9,9,11,0.95) 0%, rgba(9,9,11,0.3) 55%, transparent 100%)" }} />
      <div className="absolute bottom-4 left-0 right-0 px-4 text-center">
        <p className="font-black text-sm text-white/70 leading-tight truncate">{champ.name}</p>
        <p className="text-[9px] text-zinc-600 font-mono mt-0.5 uppercase tracking-widest">{champ.division}</p>
      </div>
    </div>
  );
}

export default function ChampionCarousel({ champions }) {
  const [current, setCurrent] = useState(0);
  const dragStartX = useRef(null);
  const total = champions.length;

  const prev = () => setCurrent(c => mod(c - 1, total));
  const next = () => setCurrent(c => mod(c + 1, total));

  const onPointerDown = (e) => { dragStartX.current = e.clientX; };
  const onPointerUp   = (e) => {
    if (dragStartX.current === null) return;
    const delta = e.clientX - dragStartX.current;
    if (Math.abs(delta) > 40) delta < 0 ? next() : prev();
    dragStartX.current = null;
  };

  const CARD_W = 280; // center card width px
  const CARD_H = CARD_W * (4 / 3);

  return (
    <div className="relative w-full select-none">

      {/* ── Stage ── */}
      <div
        className="relative w-full overflow-visible"
        style={{ height: CARD_H + 80 }}
        onPointerDown={onPointerDown}
        onPointerUp={onPointerUp}
        onPointerLeave={() => { dragStartX.current = null; }}
      >
        {champions.map((champ, i) => {
          // Compute offset relative to current, clamped to [-half, half]
          let offset = mod(i - current, total);
          if (offset > Math.floor(total / 2)) offset -= total;

          // Only render visible range
          if (Math.abs(offset) > 2) return null;

          const cfg = SLOT_CONFIG[String(offset)];
          const isCenter = offset === 0;

          return (
            // KEY = champion index → stays mounted as current changes → CSS transition fires ✅
            <div
              key={i}
              onClick={() => { if (!isCenter) (offset < 0 ? prev() : next()); }}
              style={{
                position: "absolute",
                left: "50%",
                top: isCenter ? 0 : 50,
                width: CARD_W,
                // translateX centers the card then adds pixel offset
                transform: `translateX(calc(-50% + ${cfg.xPx}px)) scale(${cfg.scale}) rotate(${cfg.rotate}deg)`,
                opacity: cfg.opacity,
                zIndex: cfg.z,
                // Transition drives the animation when offset values change
                transition: [
                  "transform 0.5s cubic-bezier(0.34, 1.08, 0.64, 1)",
                  "opacity 0.45s ease",
                  "top 0.5s ease",
                ].join(", "),
                cursor: isCenter ? "grab" : "pointer",
              }}
            >
              {isCenter ? <ChampionCard champ={champ} /> : <SideCard champ={champ} />}
            </div>
          );
        })}
      </div>

      {/* ── Dots ── */}
      <div className="flex justify-center gap-2 mt-4">
        {champions.map((_, i) => (
          <button
            key={i}
            onClick={() => setCurrent(i)}
            style={{
              width: i === current ? 28 : 6,
              height: 4,
              borderRadius: 99,
              background: i === current
                ? "linear-gradient(90deg,#ef4444,#f59e0b)"
                : "rgba(63,63,70,0.6)",
              transition: "width 0.3s ease, background 0.3s ease",
            }}
          />
        ))}
      </div>

      {/* ── Prev / Next ── */}
      <div className="flex justify-center gap-3 mt-5">
        {[{ label: "← PREV", fn: prev }, { label: "NEXT →", fn: next }].map(({ label, fn }) => (
          <button
            key={label}
            onClick={fn}
            className="px-7 py-2.5 rounded-xl bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-white hover:border-red-500/40 hover:bg-zinc-800/80 transition-all text-xs font-mono tracking-widest"
          >
            {label}
          </button>
        ))}
      </div>
    </div>
  );
}
